import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";import"./chunks/assets.Bet3gYyY.js";var i=JSON.parse(`{"title":"转信工经验分享（2026）","description":"华南理工大学转专业至电子与信息学院（信息工程专业）的经验分享，含笔试内容、面试标准与备考建议","frontmatter":{"lang":"zh-CN","title":"转信工经验分享（2026）","description":"华南理工大学转专业至电子与信息学院（信息工程专业）的经验分享，含笔试内容、面试标准与备考建议","date":"2026-07-20T00:00:00.000Z","author":"十七","sidebarDepth":2},"headers":[],"relativePath":"learn/curricular/transfer_major_information_engineering_2026.md","filePath":"learn/curricular/transfer_major_information_engineering_2026.md","lastUpdated":1784566072000}`),a={name:`learn/curricular/transfer_major_information_engineering_2026.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /learn/curricular/transfer_major_information_engineering_2026.md for this page in Markdown format</div><h1 id="转信工经验分享-十七-材料—信工" tabindex="-1">转信工经验分享 十七（材料—信工） <a class="header-anchor" href="#转信工经验分享-十七-材料—信工" aria-label="Permalink to “转信工经验分享 十七（材料—信工）”">​</a></h1><h2 id="开篇及介绍" tabindex="-1">开篇及介绍 <a class="header-anchor" href="#开篇及介绍" aria-label="Permalink to “开篇及介绍”">​</a></h2><p>专业方面，华工的电子与信息学院下设有两个专业，一个是信息工程专业，另一个是电子科学与技术。专业课程上稍有区别，电科更偏射频天线一点，其他课程的话大差不差。需要注意的是，信工往年都是以转专业班的形式组建，而电科是插入班内，两个的优势缺点可以自己考量考量，想转入哪个专业。</p><p>总体来说，转入电信学院的难度没有想象中的高，按照近几年都有均分在 15％ 左右的同学成功转入，没有特别强调高绩点。没有很高绩点的同学可以靠笔试和面试来翻盘，包容程度相对较高。当然要参考当年的报录比，报录比越低，容错率越高。25 级时候大概接近 70％ 的成功率，淘汰率是往年最低。笔者的微积分不满足机械的硬性条件，但是成功转入信息工程专业。（？问就是第一个学期玩飞了）</p><p><img src="/assets/2025_see.DBINE8ph.jpg" alt="2025 年华南理工大学电子与信息学院转专业要求"></p><h2 id="转专业条件和流程" tabindex="-1">转专业条件和流程 <a class="header-anchor" href="#转专业条件和流程" aria-label="Permalink to “转专业条件和流程”">​</a></h2><p>转专业政策解释：电信学院是有调剂选项的，25 级是信工报满了而电科没有报满，有信工的同学调剂到电子科学与技术专业去（取综合分最后两个转电科，到时候会有老师联系你愿不愿意去）。数学门槛的话比较固定，不算很高，有学长说是电信学院单科百分之五十，划线作为参考标准。电信给的名额是都会用完的，录取人数是固定的，不存在录不满。</p><p>比如我是 25 级的，24 级信工如果有 7 个名额，只报名了 2 个的话，会将 24 级没有用完的 5 名额下放给 25 级的学生。不要单看你一级的报录比，实际的报录比要低一些（有上一级的名额放下来），这一点可以仔细看一下转专业要求第 9 条。25 中法班是因为报名人数比较少，在报名截至最后一天的时候通知大家取消了，不知道 26 级能不能组建成班（前提是人数要够）。中法班会出国研学，学习法语课程，但是没有保研资格，有意愿去这个班的人比较少。</p><p>大一下时候四月下旬，会公布转专业的门槛和笔试的内容，信工与电科的考试是一起进行的，范围相同，物理部分是四十分（大一下才开，大一上一般没有这个课程），高数＋线代是六十分。如果考虑转电信学院的话，在出门槛和考试范围后就可以开始准备了，五一少玩点嗷。</p><h2 id="笔试及面试" tabindex="-1">笔试及面试 <a class="header-anchor" href="#笔试及面试" aria-label="Permalink to “笔试及面试”">​</a></h2><p>在五月初的时候（五一后，大概是 5.7 日左右）进行笔试，笔试后大概两天就会出面试名单，面试完一至两天出总录取名单。题目在信工转专业群里面有比较完整版（由其他学长学姐整理的），考试时间很紧张，11 道数学小题，6 道数学大题，其中线代部分考的很难，有一道半的证明题。大物好像是 10 填空 10 选择吧，加起来是两个小时时间，题量很大，要抓紧写。题目可以进群里面找，去年和往年有部分重复。（群号最后给了，第二个学期确定转信工，再进都来得及）</p><h2 id="面试标准及老师提问" tabindex="-1">面试标准及老师提问 <a class="header-anchor" href="#面试标准及老师提问" aria-label="Permalink to “面试标准及老师提问”">​</a></h2><p>参考标准大概如下：</p><ol><li><strong>绩点</strong>，和学习能力相关。即使你是不相关的专业，你的均分最好也要好看些，这是老师评判你学习能力的一大标准，老师没那么多功夫去一点点看你的成绩，只能是扫一眼，均分越高越有优势。注意要仔细看每一门课的学分和考核要求，别按自己想的来，有的水课很占分，想转专业的话还是蛮重要的。思政课别太低，可以认过来。</li><li><strong>英语水平</strong></li><li><strong>科研及竞赛潜质</strong>，如果有比赛经历和项目实践等会有较大优势</li><li><strong>表现的心理素质</strong></li></ol><p>提问的话比较随机，因为我们当时笔试结束后就已经是确定录取名额了，老师更侧重于和学生聊天。面试一个人是三分钟自我介绍，四分钟老师提问，等待面试期间不能玩电子设备，会上交，面完可以拿手机走了。一般就是根据你的自我介绍，来提一些相关的问题，所以如果你不确定的话／有编的成分，就要谨慎一些，老师可能会就某个感兴趣的部分提问了。还会提问一些和专业相关的内容，比如你为了转信工做了些什么，有没有相关的竞赛或者实践，来考验你的潜质，建议这方面多准备一点点。</p><p>我记得当时有一个老师负责教人工智能导论，她就提问了人工智能网课相关的东西，但是我全是刷过去的也不知道什么，瞎编了。另一个老师提问了社团相关的问题。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>转信工的难度并没有想象的高，但是千万别掉以轻心，最重要的是大一上的均分好看些，数学和英语考的高一点。大概这些，如果还有不懂的就进信工转专业群里面来提问：1037507331</p>`,19)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};